CAL_status CAL_GPIO_Toggle(GPIO_TypeDef* GPIOx, uint16_t GPIO_Pin)
{
  UNITY_LINE_TYPE cmock_line = TEST_LINE_NUM;
  CMOCK_CAL_GPIO_Toggle_CALL_INSTANCE* cmock_call_instance;
  UNITY_SET_DETAIL(CMockString_CAL_GPIO_Toggle);
  cmock_call_instance = (CMOCK_CAL_GPIO_Toggle_CALL_INSTANCE*)CMock_Guts_GetAddressFor(Mock.CAL_GPIO_Toggle_CallInstance);
  Mock.CAL_GPIO_Toggle_CallInstance = CMock_Guts_MemNext(Mock.CAL_GPIO_Toggle_CallInstance);
  if (Mock.CAL_GPIO_Toggle_IgnoreBool)
  {
    UNITY_CLR_DETAILS();
    if (cmock_call_instance == NULL)
      return Mock.CAL_GPIO_Toggle_FinalReturn;
    memcpy((void*)(&Mock.CAL_GPIO_Toggle_FinalReturn), (void*)(&cmock_call_instance->ReturnVal),
         sizeof(CAL_status[sizeof(cmock_call_instance->ReturnVal) == sizeof(CAL_status) ? 1 : -1])); /* add CAL_status to :treat_as_array if this causes an error */
    return cmock_call_instance->ReturnVal;
  }
  if (!Mock.CAL_GPIO_Toggle_CallbackBool &&
      Mock.CAL_GPIO_Toggle_CallbackFunctionPointer != NULL)
  {
    CAL_status cmock_cb_ret = Mock.CAL_GPIO_Toggle_CallbackFunctionPointer(GPIOx, GPIO_Pin, Mock.CAL_GPIO_Toggle_CallbackCalls++);
    UNITY_CLR_DETAILS();
    return cmock_cb_ret;
  }
  UNITY_TEST_ASSERT_NOT_NULL(cmock_call_instance, cmock_line, CMockStringCalledMore);
  cmock_line = cmock_call_instance->LineNumber;
  if (cmock_call_instance->CallOrder > ++GlobalVerifyOrder)
    UNITY_TEST_FAIL(cmock_line, CMockStringCalledEarly);
  if (cmock_call_instance->CallOrder < GlobalVerifyOrder)
    UNITY_TEST_FAIL(cmock_line, CMockStringCalledLate);
  if (!cmock_call_instance->IgnoreArg_GPIOx)
  {
    UNITY_SET_DETAILS(CMockString_CAL_GPIO_Toggle,CMockString_GPIOx);
    if (cmock_call_instance->Expected_GPIOx == NULL)
      { UNITY_TEST_ASSERT_NULL(GPIOx, cmock_line, CMockStringExpNULL); }
    else
      { UNITY_TEST_ASSERT_EQUAL_MEMORY_ARRAY((void*)(cmock_call_instance->Expected_GPIOx), (void*)(GPIOx), sizeof(GPIO_TypeDef), cmock_call_instance->Expected_GPIOx_Depth, cmock_line, CMockStringMismatch); }
  }
  if (!cmock_call_instance->IgnoreArg_GPIO_Pin)
  {
    UNITY_SET_DETAILS(CMockString_CAL_GPIO_Toggle,CMockString_GPIO_Pin);
    UNITY_TEST_ASSERT_EQUAL_HEX16(cmock_call_instance->Expected_GPIO_Pin, GPIO_Pin, cmock_line, CMockStringMismatch);
  }
  if (Mock.CAL_GPIO_Toggle_CallbackFunctionPointer != NULL)
  {
    cmock_call_instance->ReturnVal = Mock.CAL_GPIO_Toggle_CallbackFunctionPointer(GPIOx, GPIO_Pin, Mock.CAL_GPIO_Toggle_CallbackCalls++);
  }
  if (cmock_call_instance->ReturnThruPtr_GPIOx_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(GPIOx, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)GPIOx, (const void*)cmock_call_instance->ReturnThruPtr_GPIOx_Val,
      cmock_call_instance->ReturnThruPtr_GPIOx_Size);
  }
  UNITY_CLR_DETAILS();
  return cmock_call_instance->ReturnVal;
}

